def __init__(self, detail=None, code=None):
        if detail is None:
            detail = self.default_detail
        if code is None:
            code = self.default_code

        # For validation failures, we may collect many errors together,
        # so the details should always be coerced to a list if not already.
        if isinstance(detail, tuple):
            detail = list(detail)
        elif not isinstance(detail, dict) and not isinstance(detail, list):
            detail = [detail]

        self.detail = _get_error_details(detail, code)

def register_objects(self, typ, *args):
        self.ensure_middleware_installed()
        for arg in args:
            ident = self.get_identifier()
            objects = self.objects
            if objects is None:
                # This can happen if the SilkyMiddleware.process_request is not
                # called for whatever reason. Perhaps if another piece of
                # middleware is not playing ball.
                self._raise_not_configured(
                    'Attempt to register object of type %s without initialisation. '
                )
            if typ not in objects:
                self.objects[typ] = {}
            self.objects[typ][ident] = arg

def process_request(self, request):
        user = getattr(request, 'user', None)
        if user:
            locale_profile = getattr(user, 'locale_profile', None)
            if locale_profile:
                if locale_profile.language:
                    translation.activate(language=locale_profile.language)

                if locale_profile.timezone:
                    timezone.activate(
                        timezone=pytz.timezone(zone=locale_profile.timezone)
                    )
                else:
                    timezone.deactivate()

def create_connection_slice_for_sync_webhook_control_context(
    iterable, info: "ResolveInfo", args, connection_type, allow_sync_webhooks
):
    edges_with_context = []
    sliced_connection = create_connection_slice(iterable, info, args, connection_type)

    for edge in sliced_connection.edges:
        node = edge.node
        edge.node = SyncWebhookControlContext(
            node=node, allow_sync_webhooks=allow_sync_webhooks
        )
        edges_with_context.append(edge)
    sliced_connection.edges = edges_with_context
    return sliced_connection
